const filters = $input.item.json.body.filters || {};
const page = $input.item.json.body.page || 1;
const limit = $input.item.json.body.limit || 10;
const offset = (page - 1) * limit;

const conditions = [];
const params = [];
let paramIndex = 1;

let query = `SELECT e.id, e.nombre_empresa AS nombre, e.razon_social, e.cif, e.created_at, e.activo, e.id_tipo_empresa,
t.tipo_empresa AS tipo, e.id_comerciales, NULLIF(CONCAT(com.nombre, ' ', com.primer_apellido), ' ') AS comercial, COUNT(DISTINCT d.id) AS direcciones, 
COUNT(DISTINCT c.id) AS contactos, COUNT(*) OVER() AS total_count,
COUNT(*) FILTER (WHERE e.activo = true) OVER() AS total_activos, COUNT(*) FILTER (WHERE e.activo = false) OVER() AS total_inactivos
FROM empresa e 
LEFT JOIN tipo_empresa t ON t.id = e.id_tipo_empresa
LEFT JOIN comerciales com ON com.id = e.id_comerciales
LEFT JOIN direccion_empresa d ON d.id_empresa = e.id 
LEFT JOIN contacto_empresa c ON c.id_empresa = e.id 
WHERE 1=1`;

if (filters.searchText && filters.searchText.trim() !== '') {
  conditions.push(`(e.nombre_empresa ILIKE $${paramIndex})`);
  params.push(`%${filters.searchText}%`);
  paramIndex++;
}

if (filters.tipo && filters.tipo.trim() !== '') {
  conditions.push(`t.tipo_empresa = $${paramIndex}`);
  params.push(filters.tipo);
  paramIndex++;
}

if (filters.status && filters.status.trim() !== '') {
  if (filters.status === 'activa') {
    conditions.push(`e.activo = true`);
  } else if (filters.status === 'baja') {
    conditions.push(`e.activo = false`);
  }
}

if (conditions.length > 0) {
  query += ' AND ' + conditions.join(' AND ');
}

query += ' GROUP BY e.id, e.nombre_empresa, t.tipo_empresa, com.nombre, com.primer_apellido';
query += ' ORDER BY e.created_at ASC';
query += ` LIMIT ${limit} OFFSET ${offset}`;

return [{
  json: {
    query: query,
    params: params.join(',')
  }
}];

const body = $input.item.json.body;

const fields = ['nombre_empresa', 'razon_social', 'cif', 'id_tipo_empresa', 'activo'];
const values = [body.empresaData.nombre, body.empresaData.razonSocial, body.empresaData.cif, body.empresaData.id_tipo_empresa, body.empresaData.activo];

if (body.empresaData.id_comerciales !== null && body.empresaData.id_comerciales !== undefined) {
  fields.push('id_comerciales');
  values.push(body.empresaData.id_comerciales);
}

const placeholders = values.map((_, i) => `$${i + 1}`).join(', ');

return [{
  json: {
    query: `INSERT INTO empresa (${fields.join(', ')})
            VALUES (${placeholders})
            RETURNING id, nombre_empresa AS nombre, razon_social, cif, id_tipo_empresa, id_comerciales, activo, created_at`,
    params: values.join(',')
  }
}];

const jwt = require('jsonwebtoken');

const JWT_SECRET = 'passEncriptada';
const PUBLIC_ACTIONS = ['getRole'];

const body = $json.body;
const action = body?.action || '';

if (PUBLIC_ACTIONS.includes(action)) {
  return [{ json: { ...$json, _bypass: true } }];
}

const headers = $json.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';
const bodyToken  = body?.token || '';
const rawToken   = authHeader || bodyToken;

const token = rawToken.replace('Bearer ', '').trim();

if (!token) {
  return [{ json: { _authError: true, status: 401, message: 'Token no proporcionado' } }];
}

try {
  const decoded = jwt.verify(token, JWT_SECRET);
  return [{
    json: {
      ...$json,
      _auth: { id: decoded.id, email: decoded.email, role: decoded.role }
    }
  }];
} catch (err) {
  return [{ json: { _authError: true, status: 401, message: 'Token invÃ¡lido o expirado - ' + err.message } }];
}
